.darma-loader-darma-custom-169 {
  color: var(--loader-color, #2563eb);
width: 45px;
aspect-ratio: 1;
--c: linear-gradient(135deg,currentColor,var(--loader-secondary-color, #60a5fa));
--m: radial-gradient(farthest-side,currentColor 90%,#0000);
background: var(--c),var(--m),var(--c);
background-size:16px 8px,10px 10px;
background-repeat: no-repeat;
animation:
darma-loader-darma-custom-169-l19-1 .5s infinite alternate,
darma-loader-darma-custom-169-l19-2 4s infinite linear .5s;
}
@keyframes darma-loader-darma-custom-169-l19-1 {
0%,10% {background-position: calc(50% - 8px) 50%,50% 10%,calc(50% + 8px) 50%}
80%,100% {background-position: -20px 50%,50% 50%,calc(100% + 20px) 50%}
}
@keyframes darma-loader-darma-custom-169-l19-2 {
0% ,24.99% {transform: rotate(0)}
25%,49.99% {transform: rotate(90deg)}
50%,74.99% {transform: rotate(180deg)}
75%,100% {transform: rotate(270deg)}
}

